@internal_g = external hidden global i32

define i32 @does_not_alias_errno_internal_global(float %f) {
entry:
  store i32 42, ptr @internal_g, align 4
  %call = call float @sinf(float %f)
  %v = load i32, ptr @internal_g, align 4
  ret i32 %v
}

